sql.where:
a.del_flag = '0'

	AND a.park_id = #{asset.parkId}
	AND a.building_id = #{asset.buildingId}
	AND a.floor_no = #{asset.floorNo}
	AND a.room_id = #{asset.roomId}
	AND a.asset_code LIKE CONCAT('%', #{asset.assetCode}, '%')
	AND a.asset_name LIKE CONCAT('%', #{asset.assetName}, '%')
	AND a.asset_category = #{asset.assetCategory}
	AND a.asset_status = #{asset.assetStatus}
